import React from "react";

const Values = {
    title: 'När man känner att ingen lyssnar',
    paragraphs: [
        'Gulderen försökte hitta stöd och hjälp hos hennes församling, men kände inte att hon blev lyssnad på. Hon upplevde att det fanns en rädsla för att prata om våldet och det som hände i hennes relation.',
    ],
    video: {
        title: 'När man känner att ingen lyssnar',
        link: 'https://www.youtube-nocookie.com/embed/3ark5uRvXr4'
    },
    reflect: [
        'Varför tror du att det kan vara svårt att prata om våld i nära relation?',
    ],
}
export default Values;
